import './NavigationDrawer.scss';

import { Divider } from ':components/Divider';
import { Icon } from ':components/Icon';
import { IconButton } from ':components/IconButton';
import { Tooltip } from ':components/Tooltip';
import { Typography } from ':components/Typography';
import { useDeviceSize } from ':helpers';
import { classNames } from ':helpers/classnames';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { FC, ReactNode } from 'react';
import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';

import type { Groups, NavigationDrawerProps } from './NavigationDrawer.types';
import { NavigationItemSkeleton } from './NavigationItemSkeleton';

export const NavigationDrawer: FC<NavigationDrawerProps> = ({
	className,
	groups,
	isGroupDivider = true,
	isGroupTitle = true,
	active,
	bottom,
	onClickItem,
	isOpen = false,
	mobileOnOutsideClick,
	onOpen,
	onClose,
	disableMobileView = false,
	expandedItems: expandedItemsProp,
	onExpandedItemsChange,
	defaultExpandedItems = {},
}: NavigationDrawerProps) => {
	// Определяем, является ли компонент контролируемым
	// Компонент считается контролируемым, если переданы onOpen или onClose колбэки
	const isControlled = onOpen !== undefined || onClose !== undefined;

	// Внутреннее состояние для неконтролируемого режима
	const [internalIsExpanded, setInternalIsExpanded] = useState<boolean>(isOpen);

	// Используем внешнее состояние для контролируемого режима, внутреннее для неконтролируемого
	const isExpanded = isControlled ? isOpen : internalIsExpanded;

	// Функция для изменения состояния (работает только в неконтролируемом режиме)
	const setIsExpanded = (value: boolean | ((prev: boolean) => boolean)) => {
		if (!isControlled) {
			setInternalIsExpanded(value);
		}
	};

	const [activeItem, setActiveItem] = useState(() => active ?? '');

	// Управление состоянием раскрытых вложенных пунктов
	const isExpandedItemsControlled = expandedItemsProp !== undefined && onExpandedItemsChange !== undefined;
	const [internalExpandedItems, setInternalExpandedItems] = useState<Record<string, boolean>>(defaultExpandedItems);
	const expandedItems = isExpandedItemsControlled ? (expandedItemsProp ?? {}) : internalExpandedItems;
	// Состояние для отслеживания элементов, которые недавно завершили загрузку
	const [recentlyLoadedItems, setRecentlyLoadedItems] = useState<Set<string>>(new Set());
	const timeoutRefs = useRef<Map<string, NodeJS.Timeout>>(new Map());

	const { isExtraSmallDevice } = useDeviceSize();

	useEffect(() => {
		if (!isExtraSmallDevice) {
			return;
		}
		if (!isControlled) {
			setInternalIsExpanded(isOpen);
		}
	}, [isExtraSmallDevice, isOpen, isControlled]);

	useEffect(() => {
		if (!isControlled) {
			setInternalIsExpanded(isOpen);
		}
	}, [isOpen, isControlled]);

	// В контролируемом режиме не вызываем колбэки при изменении isExpanded,
	// так как они должны вызываться только при действиях пользователя
	// В неконтролируемом режиме вызываем колбэки при изменении внутреннего состояния
	useEffect(() => {
		if (!isControlled) {
			if (internalIsExpanded) {
				onOpen?.();
			} else {
				onClose?.();
			}
		}
	}, [internalIsExpanded, isControlled, onOpen, onClose]);

	useEffect(() => {
		setActiveItem(active);
	}, [active]);

	// Состояние для отслеживания предыдущего состояния загрузки
	const prevLoadingState = useRef<Map<string, boolean>>(new Map());

	// Отслеживаем изменения состояния загрузки элементов
	useEffect(() => {
		const checkLoadingItems = (items: any[], parentPath = '') => {
			items.forEach(item => {
				const itemKey = `${parentPath}${item.path}`;
				const wasLoading = prevLoadingState.current.get(itemKey);
				const isCurrentlyLoading = item.isLoading;

				// Обновляем состояние загрузки
				prevLoadingState.current.set(itemKey, isCurrentlyLoading);

				// Если элемент был в состоянии загрузки, но теперь загрузка завершена
				if (wasLoading && !isCurrentlyLoading) {
					// Элемент завершил загрузку - добавляем в список для анимации
					setRecentlyLoadedItems(prev => new Set([...prev, itemKey]));

					// Убираем из списка через 300ms (длительность анимации)
					const existingTimeout = timeoutRefs.current.get(itemKey);
					if (existingTimeout) {
						clearTimeout(existingTimeout);
					}

					const timeout = setTimeout(() => {
						setRecentlyLoadedItems(prev => {
							const newSet = new Set(prev);
							newSet.delete(itemKey);
							return newSet;
						});
						timeoutRefs.current.delete(itemKey);
					}, 300);

					timeoutRefs.current.set(itemKey, timeout);
				}

				// Рекурсивно проверяем дочерние элементы
				if (item.children) {
					checkLoadingItems(item.children, `${itemKey}-`);
				}
			});
		};

		// Проверяем все группы
		groups.forEach(group => checkLoadingItems(group.items));
		if (bottom) {
			bottom.forEach(group => checkLoadingItems(group.items));
		}

		// Очищаем таймауты при размонтировании
		return () => {
			timeoutRefs.current.forEach(timeout => clearTimeout(timeout));
			timeoutRefs.current.clear();
		};
	}, [groups, bottom]);

	const handleItemClick = useCallback(
		(path: string, level = 0): void => {
			// Активируем элемент, на который кликнули
			setActiveItem(path);
			onClickItem?.(path);
		},
		[onClickItem],
	);

	const handleToggleExpanded = useCallback(
		(path: string): void => {
			const newExpanded = {
				...expandedItems,
				[path]: !expandedItems[path],
			};
			if (isExpandedItemsControlled) {
				onExpandedItemsChange?.(newExpanded);
			} else {
				setInternalExpandedItems(newExpanded);
			}
		},
		[expandedItems, isExpandedItemsControlled, onExpandedItemsChange],
	);

	const getItemList = useCallback(
		(lists: Groups[], prevItemsCount = -1, level = 0): ReactNode[] => {
			const nodes: ReactNode[] = [];

			// считает сколько айтемов уже было обработано начиная с входной длины (нужна для сложения айтемов верхних и нижних груп)
			// это позволяет задать задержку анимации для каскадного эффекта при открытии меню
			let itemAnimationDelayCounter = prevItemsCount;

			if (lists) {
				for (const [index, { title, items }] of lists.entries()) {
					nodes.push(
						<div className="list__wrapper" role="menu" key={index}>
							{isGroupTitle && title && level === 0 && (
								<div className="list__wrapper-title">
									<Typography variant="overline">{title}</Typography>
								</div>
							)}
							{items?.map(item => {
								itemAnimationDelayCounter++;

								// Если элемент в состоянии загрузки, показываем скелетон
								if (item.isLoading) {
									return <NavigationItemSkeleton key={item.name} isChild={level > 0} animated={true} />;
								}

								const hasChildren = item.children && item.children.length > 0;
								const isItemExpanded = expandedItems[item.path];

								// Для дочерних элементов проверяем активность самого элемента
								const isItemActive = item.path === activeItem;
								// Для родительских элементов проверяем, активен ли какой-то из дочерних
								const isChildActive =
									level === 0 && hasChildren
										? (() => {
												return item.children?.some(child => child.path === activeItem) || false;
											})()
										: false;

								// Проверяем, нужно ли применить анимацию появления
								const itemKey = level > 0 ? `${item.path}-${item.path}` : item.path;
								const shouldAnimate = recentlyLoadedItems.has(itemKey);

								const itemNodeKey = item.name;
								const commonProps = {
									className: classNames('list__wrapper-item', {
										['list__wrapper-item--active']: (isItemActive || isChildActive) && !item.disableActive,
										['list__wrapper-item--child']: level > 0,
										['navigation-item-fade-in']: shouldAnimate,
									}),
									tabIndex: 0,
									role: 'menuitem',
									'aria-label': item.name,
									'aria-selected': (isItemActive || isChildActive) && !item.disableActive,
									...(hasChildren && { 'aria-expanded': isItemExpanded }),
								};

								const content = (
									<>
										{(isItemActive || isChildActive) && !item.disableActive && <span className="indicator"></span>}
										<>
											{level === 0 && (
												<Tooltip title={item.name} disableHover={isExpanded}>
													<Icon className="icon" size="large" iconName={item.icon} />
												</Tooltip>
											)}
											<span
												className="list__wrapper-item-text"
												style={{
													transitionDelay: isExpanded ? itemAnimationDelayCounter * 50 + 'ms' : '0ms',
												}}
											>
												<Typography className="typography" variant="body3">
													{item.name}
												</Typography>
											</span>
											{hasChildren && (
												<Icon
													className={classNames('expand-icon', {
														['expand-icon--expanded']: isItemExpanded,
													})}
													size="medium"
													iconName={Icons.NavArrowDown}
												/>
											)}
										</>
									</>
								);

								const itemNodes: ReactNode[] = [];

								if (item.href && !hasChildren) {
									const linkProps = {
										...commonProps,
										href: item.href,
										onClick: (): void => handleItemClick(item.path, level),
										...(item.target && { target: item.target }),
										...(item.rel && { rel: item.rel }),
									};
									itemNodes.push(
										<Typography key={itemNodeKey} variant="nativeLink" {...linkProps}>
											{content}
										</Typography>,
									);
								} else {
									itemNodes.push(
										<button
											key={itemNodeKey}
											{...commonProps}
											disabled={item.disabled}
											onClick={(): void => {
												if (hasChildren) {
													// Если Drawer свернут, раскрываем его по клику на родительский пункт
													if (!isExpanded) {
														if (isControlled) {
															onOpen?.();
														} else {
															setIsExpanded(true);
														}
													}
													handleToggleExpanded(item.path);
												} else {
													handleItemClick(item.path, level);
												}
											}}
										>
											{content}
										</button>,
									);
								}

								// Рендерим вложенные элементы всегда, а состояние сворачивания управляем классом
								if (hasChildren && level < 1) {
									const childGroups: Groups[] = [{ items: item.children! }];
									const childNodes = getItemList(childGroups, itemAnimationDelayCounter, level + 1);
									itemNodes.push(
										<div
											key={`${item.name}-children`}
											className={classNames('list__wrapper-children', {
												['list__wrapper-children--collapsed']: !isItemExpanded || !isExpanded,
											})}
										>
											{childNodes}
										</div>,
									);
								}

								return itemNodes;
							})}
						</div>,
					);
					if (isGroupDivider && index !== lists.length - 1 && level === 0) {
						nodes.push(
							<div className="list__divider" key={'divider' + index}>
								<Divider />
							</div>,
						);
					}
				}
			}

			return nodes;
		},
		[activeItem, handleItemClick, handleToggleExpanded, isExpanded, isGroupDivider, isGroupTitle, expandedItems],
	);

	// считает общее кол-во айтемов в основной группе. Нужно для расчета задержки анимации появления айтемов buttonGroup
	const groupsItemsCount = useMemo(() => {
		let totalItems = 0;
		for (const group of groups) {
			totalItems += group.items.length;
		}
		return totalItems;
	}, [groups]);

	const topGroups = useMemo(() => getItemList(groups), [groups, getItemList]);
	const bottomGroups = useMemo(() => getItemList(bottom, groupsItemsCount), [bottom, getItemList, groupsItemsCount]);

	const handleTriggerButton = (): void => {
		if (isControlled) {
			// В контролируемом режиме вызываем соответствующий колбэк
			if (isExpanded) {
				onClose?.();
			} else {
				onOpen?.();
			}
		} else {
			// В неконтролируемом режиме изменяем внутреннее состояние
			setInternalIsExpanded(prev => !prev);
		}
	};

	return (
		<>
			{isExtraSmallDevice && isExpanded && !disableMobileView && (
				<div className="dsb-navigation-drawer-backdrop" onClick={mobileOnOutsideClick} />
			)}
			<div
				data-testid="NavigationDrawer"
				className={classNames(
					'dsb-navigation-drawer',
					{ ['dsb-navigation-drawer--expanded']: isExpanded },
					[className],
					isExtraSmallDevice && !disableMobileView && 'dsb-navigation-drawer-mobile',
				)}
			>
				<nav className={classNames('dsb-navigation-drawer__container')}>
					{(!isExtraSmallDevice || disableMobileView) && (
						<div className="trigger-button">
							<IconButton
								size="large"
								iconName={isExpanded ? Icons.MenuOpen : Icons.Menu}
								onClick={handleTriggerButton}
							/>
						</div>
					)}
					<div className="list-top">{groups && <div className={classNames('list')}>{topGroups}</div>}</div>

					<div className="list-bottom">
						{bottom && (
							<div className={classNames('list')}>
								<div className="list__divider">
									<Divider />
								</div>
								{bottomGroups}
							</div>
						)}
					</div>
				</nav>
			</div>
		</>
	);
};
